import{_ as e,o as n,c as s,ag as t}from"./chunks/framework.CanvC6-R.js";const u=JSON.parse('{"title":"Functions in Bliss","description":"","frontmatter":{},"headers":[],"relativePath":"language/language_reference/functions.md","filePath":"language/language_reference/functions.md"}'),i={name:"language/language_reference/functions.md"};function p(l,a,o,c,r,d){return n(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="functions-in-bliss" tabindex="-1">Functions in Bliss <a class="header-anchor" href="#functions-in-bliss" aria-label="Permalink to &quot;Functions in Bliss&quot;">​</a></h1><p>Functions are defined using the <code>fx</code> keyword.</p><h2 id="definition-syntax" tabindex="-1">Definition Syntax <a class="header-anchor" href="#definition-syntax" aria-label="Permalink to &quot;Definition Syntax&quot;">​</a></h2><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fx &lt;name&gt;( &lt;arg1&gt;: &lt;type1&gt;, &lt;arg2&gt;: &lt;type2&gt; ) -&gt; &lt;ReturnType&gt; {</span></span>
<span class="line"><span>    // statements or expressions</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>The return type is optional. If omitted, the function returns nothing.</p><h2 id="call-syntax" tabindex="-1">Call Syntax <a class="header-anchor" href="#call-syntax" aria-label="Permalink to &quot;Call Syntax&quot;">​</a></h2><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;name&gt;( &lt;arg1&gt;, &lt;arg2&gt; );</span></span></code></pre></div><h2 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-label="Permalink to &quot;Rules&quot;">​</a></h2><ul><li>A function definition is itself a statement.</li><li>Arguments are written as <code>&lt;name&gt;: &lt;type&gt;</code> pairs, separated by commas.</li><li>A function can be defined with no arguments and/or no return type.</li></ul><h2 id="passing-conventions" tabindex="-1">Passing Conventions <a class="header-anchor" href="#passing-conventions" aria-label="Permalink to &quot;Passing Conventions&quot;">​</a></h2><p>Bliss has built-in passing conventions that cannot be changed:</p><ul><li><strong>Primitives</strong> (scalars) are always <strong>passed by value</strong> — a copy is made automatically.</li><li><strong>Arrays and <code>data</code> types</strong> are always <strong>passed by reference</strong> — a pointer is passed instead.</li></ul><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fx increment( x: i32 ) {</span></span>
<span class="line"><span>    // x is a copy — the original is unaffected</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fx fill( buffer: u8[] ) {</span></span>
<span class="line"><span>    // buffer is a reference — modifications affect the original</span></span>
<span class="line"><span>}</span></span></code></pre></div><blockquote><p>Taking a reference of a primitive is not permitted.</p></blockquote><h2 id="copying" tabindex="-1">Copying <a class="header-anchor" href="#copying" aria-label="Permalink to &quot;Copying&quot;">​</a></h2><p>When passing arrays or <code>data</code> types, Bliss provides two mechanisms to pass a copy instead of a reference.</p><h3 id="_1-copy-in-the-argument-definition" tabindex="-1">1. Copy in the Argument Definition <a class="header-anchor" href="#_1-copy-in-the-argument-definition" aria-label="Permalink to &quot;1. Copy in the Argument Definition&quot;">​</a></h3><p>Placing <code>copy</code> in the argument declaration allocates space for the entire entity <strong>within the function&#39;s own stack frame</strong>:</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fx process( items: copy u8[size] ) {</span></span>
<span class="line"><span>    // items is a full copy living in this function&#39;s frame</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_2-copy-at-the-call-site" tabindex="-1">2. Copy at the Call Site <a class="header-anchor" href="#_2-copy-at-the-call-site" aria-label="Permalink to &quot;2. Copy at the Call Site&quot;">​</a></h3><p>Placing <code>copy</code> at the call site allocates a new copy <strong>on the heap</strong> and passes a pointer to it:</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fx process( items: u8[] ) {</span></span>
<span class="line"><span>    // receives a pointer to a heap-allocated copy</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>process( copy buffer );</span></span></code></pre></div><h3 id="difference" tabindex="-1">Difference <a class="header-anchor" href="#difference" aria-label="Permalink to &quot;Difference&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th><code>copy</code> in argument</th><th><code>copy</code> at call site</th></tr></thead><tbody><tr><td>Where copy lives</td><td>Function&#39;s stack frame</td><td>Heap</td></tr><tr><td>What is passed</td><td>The value itself</td><td>Pointer to heap copy</td></tr><tr><td>Size required in signature</td><td>✅ Yes</td><td>❌ No</td></tr></tbody></table><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fx add( x: i32, y: i32 ) -&gt; i32 {</span></span>
<span class="line"><span>    // x and y are copies of the passed values</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fx transform( data: copy u8[64] ) {</span></span>
<span class="line"><span>    // entire 64-byte array copied into this frame</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fx process( items: u8[] ) {</span></span>
<span class="line"><span>    // receives reference (or heap copy if called with \`copy\`)</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>process( copy myBuffer );  // heap copy passed</span></span>
<span class="line"><span>add( 3, 5 );</span></span></code></pre></div><h2 id="syntax-reference" tabindex="-1">Syntax Reference <a class="header-anchor" href="#syntax-reference" aria-label="Permalink to &quot;Syntax Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Part</th><th>Required?</th><th>Description</th></tr></thead><tbody><tr><td><code>name</code></td><td>✅</td><td>The function&#39;s identifier</td></tr><tr><td><code>( ... )</code></td><td>✅</td><td>Argument list, can be empty</td></tr><tr><td><code>-&gt; ReturnType</code></td><td>❌</td><td>The type the function returns</td></tr><tr><td><code>{ ... }</code></td><td>✅</td><td>The function body</td></tr><tr><td><code>copy</code> in argument</td><td>❌</td><td>Copies entity into the function&#39;s stack frame</td></tr><tr><td><code>copy</code> at call site</td><td>❌</td><td>Allocates a heap copy and passes a pointer</td></tr></tbody></table>`,28)])])}const g=e(i,[["render",p]]);export{u as __pageData,g as default};
